import{_ as o,o as a,c as e,ag as r}from"./chunks/framework.wqPkq5Rj.js";const i=JSON.parse('{"title":"自主性 · 放手到什么程度","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/autonomy.md","filePath":"advanced/autonomy.md","lastUpdated":1777169627000}'),u={name:"advanced/autonomy.md"};function d(q,t,l,p,n,s){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="自主性-·-放手到什么程度" tabindex="-1">自主性 · 放手到什么程度 <a class="header-anchor" href="#自主性-·-放手到什么程度" aria-label="Permalink to &quot;自主性 · 放手到什么程度&quot;">​</a></h1><p>AI 同事最大的价值不是&quot;更快地回答你的问题&quot;，而是&quot;你不用问，它自己就把事干了&quot;。</p><p>但&quot;自主&quot;不是&quot;放养&quot;。理解自主性的边界，是你和 AI 同事之间建立信任的关键。</p><hr><h2 id="自主性是一个刻度-不是开关" tabindex="-1">自主性是一个刻度，不是开关 <a class="header-anchor" href="#自主性是一个刻度-不是开关" aria-label="Permalink to &quot;自主性是一个刻度，不是开关&quot;">​</a></h2><p>想象一条线——</p><p>左边是&quot;你说一步，它做一步&quot;（这是聊天机器人）； 右边是&quot;你说一句，它干一个月&quot;（这是你最信任的老员工）。</p><p>AI 同事在中间。你可以调这个刻度。</p><p><strong>调的方式就是你写的目标和规则。</strong> 写得越具体，它的自由度越小；写得越抽象，它的发挥空间越大。两种都有用，取决于这件事你有多放心。</p><hr><h2 id="两个例子-感受一下区别" tabindex="-1">两个例子，感受一下区别 <a class="header-anchor" href="#两个例子-感受一下区别" aria-label="Permalink to &quot;两个例子，感受一下区别&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">低自主性</p><p>每天早上 9 点，把昨天 GitHub 上 merged 的 PR 列一个清单，原样发到 Slack #dev 频道。</p><p>它的自由度几乎为零——做什么、什么时候做、发到哪，全是你定的。它是一个精确的执行器。</p></div><div class="tip custom-block"><p class="custom-block-title">高自主性</p><p>你负责监测竞品动态。发现值得关注的变化时，写一份简报发到团队空间，如果是紧急情况，直接 Slack 通知我。</p><p>&quot;值得关注&quot;由它判断。&quot;紧急情况&quot;由它定义。简报的格式、长度、发的频率，都是它自己决定的。</p></div><p>两种写法都对。差别在于——你需要它执行，还是需要它判断。</p><hr><h2 id="什么时候收紧-什么时候放手" tabindex="-1">什么时候收紧，什么时候放手 <a class="header-anchor" href="#什么时候收紧-什么时候放手" aria-label="Permalink to &quot;什么时候收紧，什么时候放手&quot;">​</a></h2><p>一条简单的原则：<strong>出错成本高的事，收紧；出错成本低的事，放手。</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>建议</th></tr></thead><tbody><tr><td>内部信息整理、周报汇总</td><td>放手——格式不完美没关系，下次调</td></tr><tr><td>对外发送邮件、发布内容</td><td>收紧——加一条&quot;发送前先让我确认&quot;</td></tr><tr><td>数据分析、趋势判断</td><td>放手让它分析，但结论标注为&quot;AI 判断，待人类确认&quot;</td></tr><tr><td>删除或归档文件</td><td>收紧——&quot;只标记，不执行，等我审批&quot;</td></tr></tbody></table><p>不确定的时候，先收紧。观察它干了几次之后，觉得靠谱，再逐步放手。</p><hr><h2 id="它会自己变-聪明-吗" tabindex="-1">它会自己变&quot;聪明&quot;吗 <a class="header-anchor" href="#它会自己变-聪明-吗" aria-label="Permalink to &quot;它会自己变&quot;聪明&quot;吗&quot;">​</a></h2><p>AI 同事有记忆——它记得自己做过的事、你给过的反馈、Workspace 里的历史文件。当你告诉它&quot;以后竞品简报不用写背景段了，直接说结论&quot;，它下次就会改。</p><p><strong>这不是&quot;训练&quot;，是&quot;磨合&quot;。</strong> 和带新人一样：第一周你盯得紧，第二周松一点，一个月后你只看结果。区别是——AI 同事不会离职，你们的磨合成果会一直积累。</p><hr><h2 id="最常见的两个误区" tabindex="-1">最常见的两个误区 <a class="header-anchor" href="#最常见的两个误区" aria-label="Permalink to &quot;最常见的两个误区&quot;">​</a></h2><h3 id="误区一-写得太模糊-然后对结果不满意" tabindex="-1">误区一：写得太模糊，然后对结果不满意 <a class="header-anchor" href="#误区一-写得太模糊-然后对结果不满意" aria-label="Permalink to &quot;误区一：写得太模糊，然后对结果不满意&quot;">​</a></h3><blockquote><p>&quot;帮我管好这个 Workspace。&quot;</p></blockquote><p>这不是目标，这是愿望。它不知道&quot;管好&quot;的标准是什么，只能猜。猜错了不是它的问题。</p><h3 id="误区二-写得太细-把它变成了聊天机器人" tabindex="-1">误区二：写得太细，把它变成了聊天机器人 <a class="header-anchor" href="#误区二-写得太细-把它变成了聊天机器人" aria-label="Permalink to &quot;误区二：写得太细，把它变成了聊天机器人&quot;">​</a></h3><blockquote><p>&quot;每次我发消息时，先问我要做什么，然后等我确认，然后再做，做完再问我下一步。&quot;</p></blockquote><p>这消灭了自主性。你付出了拥有一个 AI 同事的成本，但只得到了一个等指令的工具。</p><p>好的目标在两者之间：<strong>说清楚&quot;要什么结果&quot;和&quot;什么不能做&quot;，中间的路让它自己走。</strong></p>',32)])])}const c=o(u,[["render",d]]);export{i as __pageData,c as default};
